import { execSync } from "child_process"; import fs from "fs";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commitBin(name,b64){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'v3',branch:'main',content:b64}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cbv3b.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cbv3b.json "'+url+'"',{encoding:'utf8'}); }
function commit(name,str){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'v3',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cbv3.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cbv3.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000,timeout:55000}); }catch(e){ return 'EXC:'+e.message.slice(0,150); } }
const code=Buffer.from("",'base64').toString('utf8');
const pcode=Buffer.from("",'base64').toString('utf8');
(async()=>{
  fs.writeFileSync('/tmp/u572.json', JSON.stringify({name:'Petshop Daugiau=Pigiau Šablono Kūrimo Forma v3', code:code, scope:'admin', active:true}));
  exec('curl -sk -m 30 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/u572.json "'+BASE+'/wp-json/code-snippets/v1/snippets/572"');
  fs.writeFileSync('/tmp/g.json', JSON.stringify({scope:'global', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/g.json "'+BASE+'/wp-json/code-snippets/v1/snippets/572"');
  fs.writeFileSync('/tmp/b557.json', JSON.stringify({name:'PSC P3', code:pcode, scope:'global', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/b557.json "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  var r=exec('curl -sk -m 55 "'+BASE+'/?psc_p3=1&k=ps2026"');
  exec('curl -sk -m 20 -X DELETE -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  fs.writeFileSync('/tmp/a.json', JSON.stringify({scope:'admin', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/a.json "'+BASE+'/wp-json/code-snippets/v1/snippets/572"');
  var j=null; try{ j=JSON.parse(r); }catch(e){ commit('p3_meta.json', JSON.stringify({err:(r||'').slice(0,400)})); return; }
  if(j.b64){ commitBin('v3_biggest.jpg', j.b64); delete j.b64; }
  commit('p3_meta.json', JSON.stringify(j));
  console.log('done');
})();
